"""CRUD routes — generated by doql."""
from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session
from database import get_db
import models
import schemas

router = APIRouter(prefix='/api/v1')

# ── Instrument ──

@router.get("/instruments", response_model=list[schemas.InstrumentResponse])
def list_instruments(skip: int = 0, limit: int = 100, db: Session = Depends(get_db)):
    return db.query(models.Instrument).offset(skip).limit(limit).all()

@router.get("/instruments/{item_id}", response_model=schemas.InstrumentResponse)
def get_instrument(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Instrument).filter(models.Instrument.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Instrument not found")
    return obj

@router.post("/instruments", response_model=schemas.InstrumentResponse, status_code=201)
def create_instrument(data: schemas.InstrumentCreate, db: Session = Depends(get_db)):
    obj = models.Instrument(**data.model_dump())
    db.add(obj)
    db.commit()
    db.refresh(obj)
    return obj

@router.patch("/instruments/{item_id}", response_model=schemas.InstrumentResponse)
def update_instrument(item_id: str, data: schemas.InstrumentUpdate, db: Session = Depends(get_db)):
    obj = db.query(models.Instrument).filter(models.Instrument.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Instrument not found")
    for key, val in data.model_dump(exclude_unset=True).items():
        setattr(obj, key, val)
    db.commit()
    db.refresh(obj)
    return obj

@router.delete("/instruments/{item_id}", status_code=204)
def delete_instrument(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Instrument).filter(models.Instrument.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Instrument not found")
    db.delete(obj)
    db.commit()

